CustomField.formula:
HYPERLINK(
IF( Account__c != null, "/one/one.app#/sObject/" + Account__c + "/view" ,
IF( Product__c != null, "/one/one.app#/sObject/" + Product__c + "/view",
IF( Employee__c != null, "/one/one.app#/sObject/" + Employee__c + "/view",
IF( Contact__c != null, "/one/one.app#/sObject/" + Contact__c + "/view",
IF( Opportunity__c != null, "/one/one.app#/sObject/" + Opportunity__c + "/view",
IF( Campaign__c != null, "/one/one.app#/sObject/" + Campaign__c + "/view",
IF( Case__c != null, "/one/one.app#/sObject/" + Case__c + "/view",
'FIXME'
)
)
)
) 
) 
) 
) 

, 

IF( Account__c != null, Account__r.Name,
IF( Product__c != null, Product__r.Name,
IF( Employee__c != null, Employee__r.FirstName & ' ' & Employee__r.LastName,
IF( Contact__c != null, Contact__r.FirstName & ' ' & Contact__r.LastName,
IF( Opportunity__c != null, Opportunity__r.Name,
IF( Campaign__c != null, Campaign__r.Name,
IF( Case__c != null, Case__r.Subject,
'FIXME'
)
)
)
) 
) 
) 
) 



, "_self")
